/* === structs/RastPort.js === */
/* quickjs-master/amiga/ffi/structs/RastPort.js
 *
 * Wraps a struct RastPort pointer. Exposes drawing methods that
 * delegate to Graphics.* — instances are typically obtained via
 * Window.rastPort, never allocated by user code.
 */


class RastPort extends Struct {
  /* SIZE not exposed — RastPort is allocated by Intuition. */

  /**
   * REPL help text — a human-readable constructor signature.
   *
   * @returns {string}
   */
  static get signature() {
    return `RastPort(ptr)
where:
  ptr - REQUIRED: an existing struct RastPort pointer. Typically
        obtained as win.rastPort from a Window wrapper. You cannot
        allocate a RastPort from scratch via this wrapper.

Instance methods (delegate to graphics.library):
  setColor(pen)              - SetAPen
  setBgColor(pen)            - SetBPen
  move(x, y)                 - Move (no drawing)
  draw(x, y)                 - Draw line from cursor to (x,y)
  rectFill(x1, y1, x2, y2)   - RectFill with A-pen
  text(x, y, str)            - Move + render JS string (allocates
                               and frees C-string internally)`;
  }

  /**
   * Set foreground pen.
   *
   * @param {number} pen
   * @returns {undefined}
   */
  setColor(pen) {
    globalThis.amiga.Graphics.SetAPen(this, pen);
  }

  /**
   * Set background pen.
   *
   * @param {number} pen
   */
  setBgColor(pen) {
    globalThis.amiga.Graphics.SetBPen(this, pen);
  }

  /**
   * Position the graphics cursor.
   *
   * @param {number} x
   * @param {number} y
   */
  move(x, y) {
    globalThis.amiga.Graphics.Move(this, x, y);
  }

  /**
   * Draw a line from the cursor to (x,y).
   *
   * @param {number} x
   * @param {number} y
   */
  draw(x, y) {
    globalThis.amiga.Graphics.Draw(this, x, y);
  }

  /**
   * Draw a filled rectangle.
   *
   * @param {number} x1
   * @param {number} y1
   * @param {number} x2
   * @param {number} y2
   */
  rectFill(x1, y1, x2, y2) {
    globalThis.amiga.Graphics.RectFill(this, x1, y1, x2, y2);
  }

  /**
   * Move + render a string. Allocates + frees the C string internally.
   *
   * @param {number} x
   * @param {number} y
   * @param {string} str
   */
  text(x, y, str) {
    let bytes = str.length + 1;
    let p = globalThis.amiga.allocMem(bytes);

    if (!p) {
      return;
    }

    try {
      globalThis.amiga.pokeString(p, str);
      this.move(x, y);
      globalThis.amiga.Graphics.Text(this, p, str.length);
    }

    finally {
      globalThis.amiga.freeMem(p, bytes);
    }
  }
}


/* === structs/DrawInfo.js === */
/* quickjs-master/amiga/ffi/structs/DrawInfo.js
 *
 * struct DrawInfo (intuition/screens.h). Read-only descriptor handed
 * to BOOPSI images (via SYSIA_DrawInfo / IA_DrawInfo) so they can
 * render using the correct pens and system font.
 *
 * Field offsets (2-byte alignment):
 *   +0   dri_Version    (UWORD)
 *   +2   dri_NumPens    (UWORD)
 *   +4   dri_Pens       (UWORD *)
 *   +8   dri_Font       (struct TextFont *)
 *  +12   dri_Depth      (UWORD)
 *  +14   dri_Resolution (struct {UWORD X; UWORD Y;})  → 4 bytes
 *  +18   dri_Flags      (ULONG)
 *  +22   dri_CheckMark  (struct Image *)    — 3.2R4
 *  +26   dri_AmigaKey   (struct Image *)    — 3.2R4
 *   ...reserved / private follows
 *
 * Obtained via Intuition.GetScreenDrawInfo(screen) and released
 * with Intuition.FreeScreenDrawInfo(screen, dri) — neither is
 * wrapped yet, so use raw amiga.call for now.
 */


class DrawInfo extends Struct {
  /* Allocated by Intuition; we wrap. */

  /**
   * REPL help text — human-readable constructor signature.
   *
   * @returns {string}
   */
  static get signature() {
    return `DrawInfo(ptr)
where:
  ptr - REQUIRED: existing struct DrawInfo pointer from
        Intuition.GetScreenDrawInfo(screen). Release with
        Intuition.FreeScreenDrawInfo(screen, dri) when done.

Fields (read-only getters):
  version    {number}  dri_Version, +0
  numPens    {number}  dri_NumPens, +2
  pens       {number}  ptr to UWORD pen array, +4
  font       {number}  TextFont* ptr, +8
  depth      {number}  screen depth, +12
  resolutionX {number} +14 (UWORD)
  resolutionY {number} +16 (UWORD)
  flags      {number}  dri_Flags, +18
  checkMark  {Image|null} CheckMark image, +22 (3.2R4)
  amigaKey   {Image|null} AmigaKey image, +26 (3.2R4)

Typical use (raw-FFI escape hatch, wrapper pending):
  let dri = amiga.call(IntuitionBase,
    amiga.intuition.lvo.GetScreenDrawInfo, { a0: screen.ptr });
  let d = new DrawInfo(dri);
  print(d.numPens + ' pens, depth ' + d.depth);`;
  }

  /** @returns {number} */
  get version()     { return this.read16(0); }

  /** @returns {number} */
  get numPens()     { return this.read16(2); }

  /** @returns {number} UWORD* pen array pointer */
  get pens()        { return this.read32(4); }

  /** @returns {number} TextFont* pointer */
  get font()        { return this.read32(8); }

  /** @returns {number} screen depth in bit-planes */
  get depth()       { return this.read16(12); }

  /** @returns {number} horizontal resolution */
  get resolutionX() { return this.read16(14); }

  /** @returns {number} vertical resolution */
  get resolutionY() { return this.read16(16); }

  /** @returns {number} dri_Flags bitfield */
  get flags()       { return this.read32(18); }

  /**
   * Read one entry from the pen array.
   *
   * @param {number} index — 0..numPens-1
   * @returns {number}  pen number (UWORD)
   */
  getPen(index) {
    let p = this.pens;

    if (!p || index < 0 || index >= this.numPens) return 0;

    return globalThis.amiga.peek16(p + index * 2);
  }
}


/* === structs/Menu.js === */
/* quickjs-master/amiga/ffi/structs/Menu.js
 *
 * struct Menu (intuition/intuition.h). One entry in a window's menu
 * bar; holds a chain of MenuItem via FirstItem.
 *
 * Field offsets (2-byte alignment):
 *   +0   NextMenu   (struct Menu *)
 *   +4   LeftEdge   (WORD)
 *   +6   TopEdge    (WORD)
 *   +8   Width      (WORD)
 *  +10   Height     (WORD)
 *  +12   Flags      (UWORD)
 *  +14   MenuName   (STRPTR)
 *  +18   FirstItem  (struct MenuItem *)
 *  +22   JazzX, JazzY, BeatX, BeatY (UWORD × 4) — runtime layout cache
 *  total 30
 */


class Menu extends Struct {
  /** @type {number} */
  static SIZE = 30;

  /**
   * REPL help text.
   *
   * @returns {string}
   */
  static get signature() {
    return `Menu(ptr?)
where:
  ptr? - optional existing struct Menu pointer. Omit to allocate a
         fresh 30-byte struct. Menus are typically built statically
         in C; from JS, use GadTools.CreateMenusA / LayoutMenus via
         the raw-FFI escape hatch until a wrapper lands.

Fields (getters):
  nextMenu   {number} ptr to next Menu in bar, +0
  leftEdge   {number} WORD, +4
  topEdge    {number} WORD, +6
  width      {number} WORD, +8
  height     {number} WORD, +10
  flags      {number} MENUENABLED etc., +12
  menuName   {string|null} menu label, +14 (STRPTR)
  firstItem  {MenuItem|null} first MenuItem in this menu, +18

Setters:
  nextMenu, firstItem, menuName, flags, leftEdge, topEdge,
  width, height (raw numbers/ptrs only).`;
  }

  /** @returns {number} */
  get nextMenu()   { return this.read32(0); }
  set nextMenu(v)  { this.write32(0, v | 0); }

  /** @returns {number} */
  get leftEdge()   { return this.read16(4); }
  set leftEdge(v)  { this.write16(4, v | 0); }

  /** @returns {number} */
  get topEdge()    { return this.read16(6); }
  set topEdge(v)   { this.write16(6, v | 0); }

  /** @returns {number} */
  get width()      { return this.read16(8); }
  set width(v)     { this.write16(8, v | 0); }

  /** @returns {number} */
  get height()     { return this.read16(10); }
  set height(v)    { this.write16(10, v | 0); }

  /** @returns {number} MENUENABLED = 0x0001 etc. */
  get flags()      { return this.read16(12); }
  set flags(v)     { this.write16(12, v | 0); }

  /** @returns {string|null} */
  get menuName() {
    let p = this.read32(14);
    return p ? globalThis.amiga.peekString(p, 128) : null;
  }

  /** @param {number} ptr — STRPTR (caller-managed) */
  set menuName(ptr) { this.write32(14, ptr | 0); }

  /** @returns {MenuItem|null} */
  get firstItem() {
    let p = this.read32(18);
    if (!p) return null;

    /* Circular-import-safe lookup through the global namespace. */
    let MI = globalThis.amiga && globalThis.amiga.intuition
          && globalThis.amiga.intuition.MenuItem;

    return MI ? new MI(p) : null;
  }

  set firstItem(v) { this.write32(18, (v && v.ptr) || (v | 0)); }
}


/* === structs/MenuItem.js === */
/* quickjs-master/amiga/ffi/structs/MenuItem.js
 *
 * struct MenuItem (intuition/intuition.h). Single entry in a Menu
 * (or a submenu chain).
 *
 * Field offsets (2-byte alignment):
 *   +0   NextItem    (struct MenuItem *)
 *   +4   LeftEdge    (WORD)
 *   +6   TopEdge     (WORD)
 *   +8   Width       (WORD)
 *  +10   Height      (WORD)
 *  +12   Flags       (UWORD)  — ITEMENABLED, HIGHCOMP, CHECKED etc.
 *  +14   MutualExclude (LONG)
 *  +18   ItemFill    (APTR)   — Image* or IntuiText*
 *  +22   SelectFill  (APTR)   — highlight rendering
 *  +26   Command     (BYTE)   — Amiga-key shortcut
 *  +27   pad         (BYTE)
 *  +28   SubItem     (struct MenuItem *)
 *  +32   NextSelect  (UWORD)
 *  total 34
 */


class MenuItem extends Struct {
  /** @type {number} */
  static SIZE = 34;

  /**
   * REPL help text.
   *
   * @returns {string}
   */
  static get signature() {
    return `MenuItem(ptr?)
where:
  ptr? - optional existing struct MenuItem pointer. Omit to allocate
         a fresh 34-byte struct.

Fields (getter+setter on each):
  nextItem      {number} ptr to next item, +0
  leftEdge      {number}
  topEdge       {number}
  width         {number}
  height        {number}
  flags         {number}   ITEMENABLED=1, HIGHCOMP=0x40, CHECKED=0x100,
                           CHECKIT=0x01, COMMSEQ=0x04, ITEMTEXT=0x02 ...
  mutualExclude {number}   LONG exclusion bitmask
  itemFill      {number}   APTR to Image* or IntuiText*
  selectFill    {number}   APTR for highlight
  command       {number}   BYTE — single-char Amiga-key shortcut
  subItem       {MenuItem|null} submenu ptr, or null
  nextSelect    {number}   UWORD

Flags conveniences: COMMSEQ | ITEMTEXT | ITEMENABLED is the typical
"enabled text item with a right-Amiga shortcut" combination.`;
  }

  /** @returns {number} */
  get nextItem()      { return this.read32(0); }
  set nextItem(v)     { this.write32(0, v | 0); }

  /** @returns {number} */
  get leftEdge()      { return this.read16(4); }
  set leftEdge(v)     { this.write16(4, v | 0); }

  /** @returns {number} */
  get topEdge()       { return this.read16(6); }
  set topEdge(v)      { this.write16(6, v | 0); }

  /** @returns {number} */
  get width()         { return this.read16(8); }
  set width(v)        { this.write16(8, v | 0); }

  /** @returns {number} */
  get height()        { return this.read16(10); }
  set height(v)       { this.write16(10, v | 0); }

  /** @returns {number} */
  get flags()         { return this.read16(12); }
  set flags(v)        { this.write16(12, v | 0); }

  /** @returns {number} */
  get mutualExclude() { return this.read32(14); }
  set mutualExclude(v){ this.write32(14, v | 0); }

  /** @returns {number} APTR (Image* or IntuiText*) */
  get itemFill()      { return this.read32(18); }
  set itemFill(v)     { this.write32(18, (v && v.ptr) || (v | 0)); }

  /** @returns {number} APTR */
  get selectFill()    { return this.read32(22); }
  set selectFill(v)   { this.write32(22, (v && v.ptr) || (v | 0)); }

  /** @returns {number} BYTE — Amiga-key shortcut (ASCII) */
  get command()       { return this.read8(26); }
  set command(v)      { this.write8(26, v | 0); }

  /** @returns {MenuItem|null} */
  get subItem() {
    let p = this.read32(28);
    if (!p) return null;

    return new MenuItem(p);
  }

  set subItem(v) { this.write32(28, (v && v.ptr) || (v | 0)); }

  /** @returns {number} */
  get nextSelect()    { return this.read16(32); }
  set nextSelect(v)   { this.write16(32, v | 0); }
}


/* === structs/IntuiText.js === */
/* quickjs-master/amiga/ffi/structs/IntuiText.js
 *
 * struct IntuiText (intuition/intuition.h). A rendered text element
 * passable anywhere Intuition wants text (menu items, gadgets,
 * requesters) via Intuition.PrintIText.
 *
 * Field offsets (2-byte alignment):
 *   +0   FrontPen  (UBYTE)
 *   +1   BackPen   (UBYTE)
 *   +2   DrawMode  (UBYTE)
 *   +3   pad       (UBYTE)
 *   +4   LeftEdge  (WORD)
 *   +6   TopEdge   (WORD)
 *   +8   ITextFont (struct TextAttr *)
 *  +12   IText     (STRPTR)
 *  +16   NextText  (struct IntuiText *)
 *  total 20
 *
 * Memory policy: if constructed with a JS string in the init object,
 * the wrapper allocates + owns the C string and frees it in free().
 */


class IntuiText extends Struct {
  /** @type {number} */
  static SIZE = 20;

  /**
   * REPL help text.
   *
   * @returns {string}
   */
  static get signature() {
    return `IntuiText(initOrPtr?)
where:
  initOrPtr? - one of:
    - number: wrap an existing IntuiText* pointer.
    - object: allocate + populate. Fields:
        frontPen, backPen, drawMode, leftEdge, topEdge,
        font (TextAttr|number), text (string|number), nextText.
        When 'text' is a JS string, this wrapper owns the
        allocation and frees it in free().
    - omitted: zeroed 20-byte struct.

Fields (read+write):
  frontPen, backPen, drawMode  {number} UBYTE
  leftEdge, topEdge            {number} WORD
  font                         {number} TextAttr* at +8
  text                         {string|null}  (getter decodes STRPTR)
                               {string|number} (setter, owning if str)
  nextText                     {number}

Methods: free() — releases struct + owned text allocation.`;
  }

  /**
   * @param {object|number} [initOrPtr] — see `signature`
   */
  constructor(initOrPtr) {
    if (typeof initOrPtr === 'number') {
      super(initOrPtr);
      this._textAlloc = null;
      return;
    }

    super();
    this._textAlloc = null;

    if (!initOrPtr) return;

    let i = initOrPtr;

    if (i.frontPen !== undefined) this.frontPen = i.frontPen;
    if (i.backPen  !== undefined) this.backPen  = i.backPen;
    if (i.drawMode !== undefined) this.drawMode = i.drawMode;
    if (i.leftEdge !== undefined) this.leftEdge = i.leftEdge;
    if (i.topEdge  !== undefined) this.topEdge  = i.topEdge;
    if (i.font     !== undefined) this.write32(8, ptrOf(i.font));
    if (i.text     !== undefined) this.text = i.text;
    if (i.nextText !== undefined) this.write32(16, ptrOf(i.nextText));
  }

  /**
   * Release struct memory and any owned text string. Idempotent.
   *
   * @returns {undefined}
   */
  free() {
    if (this._textAlloc) {
      globalThis.amiga.freeMem(
        this._textAlloc.ptr,
        this._textAlloc.size
      );
      this._textAlloc = null;
    }

    super.free();
  }

  /** @returns {number} UBYTE */
  get frontPen()  { return this.read8(0); }
  set frontPen(v) { this.write8(0, v | 0); }

  /** @returns {number} UBYTE */
  get backPen()   { return this.read8(1); }
  set backPen(v)  { this.write8(1, v | 0); }

  /** @returns {number} JAM1/JAM2/COMPLEMENT/INVERSVID */
  get drawMode()  { return this.read8(2); }
  set drawMode(v) { this.write8(2, v | 0); }

  /** @returns {number} */
  get leftEdge()  { return this.read16(4); }
  set leftEdge(v) { this.write16(4, v | 0); }

  /** @returns {number} */
  get topEdge()   { return this.read16(6); }
  set topEdge(v)  { this.write16(6, v | 0); }

  /**
   * Text field. Set with a string to allocate + own; set with a
   * number to use a caller-managed pointer (no auto-free).
   *
   * @param {string|number|null} value
   */
  set text(value) {
    if (this._textAlloc) {
      globalThis.amiga.freeMem(
        this._textAlloc.ptr,
        this._textAlloc.size
      );
      this._textAlloc = null;
    }

    if (value === null || value === undefined || value === 0) {
      this.write32(12, 0);
      return;
    }

    if (typeof value === 'string') {
      let bytes = value.length + 1;
      let p = globalThis.amiga.allocMem(bytes);

      if (!p) throw new Error('IntuiText.text: allocMem failed');

      globalThis.amiga.pokeString(p, value);
      this.write32(12, p);
      this._textAlloc = { ptr: p, size: bytes };
      return;
    }

    this.write32(12, value | 0);
  }

  /** @returns {string|null} */
  get text() {
    let p = this.read32(12);
    return p ? globalThis.amiga.peekString(p, 256) : null;
  }

  /** @returns {number} */
  get nextText()  { return this.read32(16); }
  set nextText(v) { this.write32(16, (v && v.ptr) || (v | 0)); }
}


/* === structs/BitMap.js === */
/* quickjs-master/amiga/ffi/structs/BitMap.js
 *
 * struct BitMap (graphics/gfx.h). Planar bitmap descriptor.
 *
 * Field offsets (2-byte alignment):
 *   +0   BytesPerRow  (UWORD)
 *   +2   Rows         (UWORD)
 *   +4   Flags        (UBYTE)
 *   +5   Depth        (UBYTE)
 *   +6   pad          (UWORD)
 *   +8   Planes       (PLANEPTR × 8)   — first 8 bitplane pointers
 *  +40   (end for classic BitMap; BitMap_V39 extends here)
 *
 * Flags: BMF_CLEAR (1), BMF_DISPLAYABLE (2), BMF_INTERLEAVED (4),
 *        BMF_STANDARD (8), BMF_MINPLANES (0x10).
 */


class BitMap extends Struct {
  /** @type {number} */
  static SIZE = 40;

  /**
   * REPL help text.
   *
   * @returns {string}
   */
  static get signature() {
    return `BitMap(ptr?)
where:
  ptr? - optional existing BitMap* pointer. Omit to allocate a raw
         40-byte BitMap header (caller still needs to AllocRaster
         the planes and fill in the Planes array).

Fields:
  bytesPerRow  {number} +0 UWORD
  rows         {number} +2 UWORD
  flags        {number} +4 UBYTE  (BMF_CLEAR/DISPLAYABLE/INTERLEAVED...)
  depth        {number} +5 UBYTE  bit-plane count (1..8)
  getPlane(i)  {number} PLANEPTR for plane i (0..depth-1)
  setPlane(i,p){undefined} write PLANEPTR

For displayable/planar operations prefer Graphics.AllocBitMap (not
yet wrapped) over manual construction.`;
  }

  /** @returns {number} */
  get bytesPerRow() { return this.read16(0); }
  set bytesPerRow(v){ this.write16(0, v | 0); }

  /** @returns {number} */
  get rows()        { return this.read16(2); }
  set rows(v)       { this.write16(2, v | 0); }

  /** @returns {number} UBYTE */
  get flags()       { return this.read8(4); }
  set flags(v)      { this.write8(4, v | 0); }

  /** @returns {number} UBYTE */
  get depth()       { return this.read8(5); }
  set depth(v)      { this.write8(5, v | 0); }

  /**
   * Get one bit-plane pointer from the Planes[] array.
   *
   * @param {number} i — 0..7
   * @returns {number} PLANEPTR (raw memory ptr)
   */
  getPlane(i) {
    if (i < 0 || i > 7) return 0;
    return this.read32(8 + i * 4);
  }

  /**
   * Set one bit-plane pointer.
   *
   * @param {number} i — 0..7
   * @param {number} ptr — PLANEPTR
   */
  setPlane(i, ptr) {
    if (i < 0 || i > 7) return;
    this.write32(8 + i * 4, ptr | 0);
  }
}


/* === structs/ColorMap.js === */
/* quickjs-master/amiga/ffi/structs/ColorMap.js
 *
 * struct ColorMap (graphics/view.h). A ViewPort's color table —
 * access is by library call (GetRGB4/SetRGB4/LoadRGB4) rather than
 * raw offsets because the internal layout varies with RTG systems.
 *
 * This wrapper exposes only the handful of fields documented as
 * stable across AmigaOS 3.x:
 *   +0   Flags    (UBYTE)
 *   +1   Type     (UBYTE)
 *   +2   Count    (UWORD)
 *   +4   ColorTable (UWORD *)  — do not rely on this with RTG
 *   +8   (internal) cm_TransparencyPlane and friends
 */


class ColorMap extends Struct {
  /* Allocated by graphics.library GetColorMap / attached to ViewPort. */

  /**
   * REPL help text.
   *
   * @returns {string}
   */
  static get signature() {
    return `ColorMap(ptr)
where:
  ptr - REQUIRED: existing ColorMap* pointer, normally read from a
        ViewPort via viewPort.colorMap (not yet wrapped) or returned
        by Graphics.GetColorMap. Lifecycle managed by graphics.library.

Fields (getters):
  flags   {number} UBYTE, +0
  type    {number} UBYTE, +1 (CMTYPE classic vs extended)
  count   {number} UWORD number of entries, +2

Prefer calling Graphics.GetRGB4(colorMap, i) for per-entry reads
rather than walking ColorTable directly; RTG systems use a deeper
internal representation.`;
  }

  /** @returns {number} UBYTE */
  get flags() { return this.read8(0); }

  /** @returns {number} UBYTE */
  get type()  { return this.read8(1); }

  /** @returns {number} UWORD */
  get count() { return this.read16(2); }
}


/* === structs/FileInfoBlock.js === */
/* quickjs-master/amiga/ffi/structs/FileInfoBlock.js
 *
 * struct FileInfoBlock (dos/dos.h). Filled by Examine/ExNext to
 * describe a file or directory entry. Must be LONG-aligned
 * (AllocDosObject handles this; our allocMem path is LONG-aligned
 * on AmigaOS).
 *
 * Field offsets (2-byte alignment; all entries LONG-aligned by
 * the AmigaOS memory allocator):
 *   +0    fib_DiskKey      (LONG, 4)
 *   +4    fib_DirEntryType (LONG, 4)   <0 = file, >0 = directory
 *   +8    fib_FileName     (char[108]) — BCPL counted string: byte 0
 *                                         is length, bytes 1..N the
 *                                         chars. 107 max chars.
 * +116    fib_Protection   (LONG, 4)
 * +120    fib_EntryType    (LONG, 4)
 * +124    fib_Size         (LONG, 4)   — bytes in the file
 * +128    fib_NumBlocks    (LONG, 4)
 * +132    fib_Date         (struct DateStamp) — 3 × LONG = 12 bytes
 * +144    fib_Comment      (char[80])  — BCPL counted
 * +224    fib_OwnerUID     (UWORD)
 * +226    fib_OwnerGID     (UWORD)
 * +228    fib_Reserved     (char[32])
 *  total 260
 */


class FileInfoBlock extends Struct {
  /** @type {number} */
  static SIZE = 260;

  /**
   * REPL help text.
   *
   * @returns {string}
   */
  static get signature() {
    return `FileInfoBlock(ptr?)
where:
  ptr? - optional existing FileInfoBlock* pointer. Omit to allocate
         a zeroed 260-byte struct. Must be LONG-aligned; allocMem
         always returns LONG-aligned memory on AmigaOS.

Fields (read-only getters):
  diskKey        {number} LONG, +0
  dirEntryType   {number} LONG, +4  (<0 file, >0 dir)
  fileName       {string} BCPL string at +8, up to 107 chars
  protection     {number} LONG, +116
  size           {number} LONG, +124 (file bytes)
  numBlocks      {number} LONG, +128
  dateDays       {number} ds_Days,     +132
  dateMinute     {number} ds_Minute,   +136
  dateTick       {number} ds_Tick,     +140
  comment        {string} BCPL string at +144
  ownerUID       {number} UWORD, +224
  ownerGID       {number} UWORD, +226

Typical use:
  let fib = new FileInfoBlock();
  let lock = Dos.Lock('RAM:', -2 /*SHARED_LOCK*/);
  if (Dos.Examine(lock, fib)) {
    print(fib.fileName + ' (' + fib.size + ' bytes)');
  }
  Dos.UnLock(lock);
  fib.free();`;
  }

  /**
   * Read a BCPL-style counted string from an offset. Byte 0 is the
   * length, bytes 1..N are the chars.
   *
   * @param   {number} off
   * @param   {number} cap — max byte count at offset (incl. length)
   * @returns {string}
   */
  _readBCPL(off, cap) {
    let len = this.read8(off);

    if (len <= 0) return '';
    if (len > cap - 1) len = cap - 1;

    let chars = [];

    for (let i = 0; i < len; i++) {
      chars.push(String.fromCharCode(this.read8(off + 1 + i)));
    }

    return chars.join('');
  }

  /** @returns {number} LONG */
  get diskKey()      { return this.read32(0); }

  /** @returns {number} LONG (<0 file, >0 directory) */
  get dirEntryType() { return this.read32(4) | 0; }

  /** @returns {string} */
  get fileName()     { return this._readBCPL(8, 108); }

  /** @returns {number} LONG protection bits */
  get protection()   { return this.read32(116); }

  /** @returns {number} LONG byte size */
  get size()         { return this.read32(124); }

  /** @returns {number} LONG */
  get numBlocks()    { return this.read32(128); }

  /** @returns {number} DateStamp.ds_Days */
  get dateDays()     { return this.read32(132); }

  /** @returns {number} DateStamp.ds_Minute */
  get dateMinute()   { return this.read32(136); }

  /** @returns {number} DateStamp.ds_Tick */
  get dateTick()     { return this.read32(140); }

  /** @returns {string} comment, BCPL string */
  get comment()      { return this._readBCPL(144, 80); }

  /** @returns {number} UWORD */
  get ownerUID()     { return this.read16(224); }

  /** @returns {number} UWORD */
  get ownerGID()     { return this.read16(226); }
}


/* === structs/InputEvent.js === */
/* quickjs-master/amiga/ffi/structs/InputEvent.js
 *
 * struct InputEvent (devices/inputevent.h). The raw input-event
 * record passed through the input handler chain. Most JS code will
 * use IDCMP_RAWKEY / VANILLAKEY via Window.messages() instead — this
 * wrapper is for low-level input-handler ports.
 *
 * Field offsets (2-byte alignment):
 *   +0   NextEvent (struct InputEvent *)
 *   +4   Class     (UBYTE)   — IECLASS_RAWKEY, RAWMOUSE, NEWPOINTERPOS...
 *   +5   SubClass  (UBYTE)
 *   +6   Code      (UWORD)
 *   +8   Qualifier (UWORD)
 *  +10   EventAddress (APTR) — union: X, Y, RawAddr, or ti_Data
 *  +14   TimeStamp (struct timeval, 8 bytes)
 *  total 22
 */


class InputEvent extends Struct {
  /** @type {number} */
  static SIZE = 22;

  /**
   * REPL help text.
   *
   * @returns {string}
   */
  static get signature() {
    return `InputEvent(ptr?)
where:
  ptr? - optional existing InputEvent* pointer. Omit to allocate a
         zeroed 22-byte struct.

Fields (read+write on primitives):
  nextEvent  {number} ptr to next event in the chain, +0
  class      {number} IECLASS_* at +4 (UBYTE)
  subClass   {number} UBYTE, +5
  code       {number} UWORD, +6
  qualifier  {number} UWORD, +8
  eventAddress {number} APTR at +10 (interpreted by class)
  seconds    {number} TimeStamp seconds at +14
  micros     {number} TimeStamp micros  at +18

IECLASS_* codes (UBYTE):
  0  NULL          — empty/reset event
  1  RAWKEY        — keyboard raw key code
  2  RAWMOUSE      — mouse movement / buttons
  3  EVENT         — generic system event
  4  POINTERPOS    — absolute pointer coord
  5  TIMER         — VBL tick`;
  }

  /** @returns {number} */
  get nextEvent()    { return this.read32(0); }
  set nextEvent(v)   { this.write32(0, (v && v.ptr) || (v | 0)); }

  /** @returns {number} UBYTE, IECLASS_* */
  get class()        { return this.read8(4); }
  set class(v)       { this.write8(4, v | 0); }

  /** @returns {number} UBYTE */
  get subClass()     { return this.read8(5); }
  set subClass(v)    { this.write8(5, v | 0); }

  /** @returns {number} UWORD */
  get code()         { return this.read16(6); }
  set code(v)        { this.write16(6, v | 0); }

  /** @returns {number} UWORD */
  get qualifier()    { return this.read16(8); }
  set qualifier(v)   { this.write16(8, v | 0); }

  /** @returns {number} APTR (class-dependent interpretation) */
  get eventAddress() { return this.read32(10); }
  set eventAddress(v){ this.write32(10, (v && v.ptr) || (v | 0)); }

  /** @returns {number} TimeStamp tv_secs */
  get seconds()      { return this.read32(14); }

  /** @returns {number} TimeStamp tv_micro */
  get micros()       { return this.read32(18); }
}


/* === structs/IORequest.js === */
/* quickjs-master/amiga/ffi/structs/IORequest.js
 *
 * struct IORequest (exec/io.h). Base "I/O message" passed to devices
 * via DoIO/SendIO/WaitIO. Size 32 bytes. Concrete devices usually
 * extend this with their own struct (see TimerRequest).
 *
 * Field offsets:
 *   +0   io_Message (struct Message) — 20 bytes
 *  +20   io_Device  (struct Device *)
 *  +24   io_Unit    (struct Unit   *)
 *  +28   io_Command (UWORD)
 *  +30   io_Flags   (UBYTE)
 *  +31   io_Error   (BYTE)
 *  total 32
 *
 * The io_Message header itself has:
 *   +0   mn_Node      (struct Node, 14 bytes)
 *  +14   mn_ReplyPort (struct MsgPort *)
 *  +18   mn_Length    (UWORD)
 */


class IORequest extends Struct {
  /** @type {number} */
  static SIZE = 32;

  /**
   * REPL help text.
   *
   * @returns {string}
   */
  static get signature() {
    return `IORequest(ptr?)
where:
  ptr? - optional existing IORequest* pointer. Omit to allocate 32
         zeroed bytes (caller still needs to fill io_Message's
         mn_ReplyPort, mn_Length, and whatever io_Command/flags the
         target device expects).

Fields:
  replyPort   {number} MsgPort* ptr at +14 (mn_ReplyPort)
  messageLen  {number} UWORD at +18 (mn_Length — struct byte size)
  device      {number} Device* ptr at +20
  unit        {number} Unit* ptr at +24
  command     {number} UWORD at +28
  flags       {number} UBYTE at +30
  error       {number} BYTE at +31

Setters exist for replyPort, messageLen, command, flags; device
and unit are normally set by OpenDevice. Read 'error' after DoIO.

See TimerRequest for a concrete specialization.`;
  }

  /** @returns {number} */
  get replyPort()   { return this.read32(14); }
  set replyPort(v)  { this.write32(14, (v && v.ptr) || (v | 0)); }

  /** @returns {number} */
  get messageLen()  { return this.read16(18); }
  set messageLen(v) { this.write16(18, v | 0); }

  /** @returns {number} */
  get device()      { return this.read32(20); }

  /** @returns {number} */
  get unit()        { return this.read32(24); }

  /** @returns {number} */
  get command()     { return this.read16(28); }
  set command(v)    { this.write16(28, v | 0); }

  /** @returns {number} UBYTE */
  get flags()       { return this.read8(30); }
  set flags(v)      { this.write8(30, v | 0); }

  /** @returns {number} BYTE (may be negative for error codes) */
  get error()       {
    let b = this.read8(31);
    /* BYTE is signed; extend from 8-bit 2s-complement. */
    return b >= 0x80 ? b - 0x100 : b;
  }
}


/* === structs/TimerRequest.js === */
/* quickjs-master/amiga/ffi/structs/TimerRequest.js
 *
 * struct timerequest (devices/timer.h). IORequest + one timeval,
 * used by timer.device for delays.
 *
 * Field offsets (continues IORequest, 2-byte aligned):
 *   +0..31  IORequest header (see IORequest.js)
 *  +32      tv_secs   (ULONG)
 *  +36      tv_micro  (ULONG)
 *  total 40
 *
 * Units: UNIT_MICROHZ (0) = µs precision; UNIT_VBLANK (1) = VBL ticks.
 * Commands: TR_ADDREQUEST (9) = "signal me after tv_secs.tv_micro",
 *           TR_GETSYSTIME (11) = "fill tv with current uptime".
 */


class TimerRequest extends IORequest {
  /** @type {number} */
  static SIZE = 40;

  /**
   * REPL help text.
   *
   * @returns {string}
   */
  static get signature() {
    return `TimerRequest(ptr?)
where:
  ptr? - optional existing struct timerequest pointer. Omit to
         allocate a zeroed 40-byte TimerRequest.

Fields (inherits IORequest + adds):
  tvSecs   {number} tv_secs,  +32 (ULONG)
  tvMicro  {number} tv_micro, +36 (ULONG)
  setTimeval(secs, micro)     convenience setter

Typical use:
  // open timer.device first (not wrapped yet — use raw FFI).
  let tr = new TimerRequest();
  tr.replyPort  = port.ptr;
  tr.messageLen = TimerRequest.SIZE;
  tr.command = 9;            // TR_ADDREQUEST
  tr.setTimeval(2, 0);       // 2 seconds
  // then Exec.DoIO(tr) or SendIO.

Commands:
  TR_ADDREQUEST = 9
  TR_GETSYSTIME = 11
  CMD_ABORTIO   = 4`;
  }

  /** @returns {number} ULONG seconds */
  get tvSecs()   { return this.read32(32); }
  set tvSecs(v)  { this.write32(32, v | 0); }

  /** @returns {number} ULONG microseconds (0..999999) */
  get tvMicro()  { return this.read32(36); }
  set tvMicro(v) { this.write32(36, v | 0); }

  /**
   * Fill both tv fields at once.
   *
   * @param {number} secs  — seconds
   * @param {number} micro — microseconds (0..999999)
   * @returns {undefined}
   */
  setTimeval(secs, micro) {
    this.tvSecs  = secs;
    this.tvMicro = micro;
  }
}


/* === structs/Screen.js === */
/* quickjs-master/amiga/ffi/structs/Screen.js
 *
 * Field offsets per intuition/screens.h (2-byte alignment):
 *   +0   NextScreen (4)
 *   +4   FirstWindow (4)
 *   +8   LeftEdge, +10 TopEdge, +12 Width, +14 Height (WORD each)
 *  +16   MouseY (2), +18 MouseX (2)
 *  +20   Flags (UWORD, 2)
 *  +22   Title (STRPTR, 4)
 *  +26   DefaultTitle (STRPTR, 4)
 *  +30   BarHeight, BarVBorder, ..., WBorBottom (9 × BYTE)
 *  +40   Font (struct TextAttr *, 4 — 1 byte pad at +39)
 */


class Screen extends Struct {
  /* SIZE not exposed — Screen is allocated by Intuition. */

  /**
   * REPL help text — a human-readable constructor signature.
   *
   * @returns {string}
   */
  static get signature() {
    return `Screen(ptr)
where:
  ptr - REQUIRED: an existing struct Screen pointer from
        Intuition.OpenScreenTags / LockPubScreen. You cannot
        allocate a Screen from scratch — only Intuition may.

Fields (read-only getters): leftEdge, topEdge, width, height,
  flags, title, barHeight, font (TextAttr wrapper).

Lifecycle is managed by Intuition.CloseScreen or UnlockPubScreen.`;
  }

  /** @returns {number} */
  get leftEdge() { return this.read16( 8); }

  /** @returns {number} */
  get topEdge()  { return this.read16(10); }

  /** @returns {number} */
  get width()    { return this.read16(12); }

  /** @returns {number} */
  get height()   { return this.read16(14); }

  /** @returns {number} */
  get flags()    { return this.read16(20); }

  /** @returns {string|null} */
  get title() {
    let p = this.read32(22);

    return p ? globalThis.amiga.peekString(p, 64) : null;
  }

  /** @returns {number} */
  get barHeight() { return this.read8(30); }

  /** @returns {TextAttr|null} */
  get font() {
    let p = this.read32(40);

    return p ? new TextAttr(p) : null;
  }
}


/* === structs/TagItem.js === */
/* quickjs-master/amiga/ffi/structs/TagItem.js
 *
 * Helpers around amiga.makeTags (raw Q1) for the wrapper layer.
 * Not a Struct subclass — TagItem arrays are owned by their builder.
 */

/**
 * Build a TagItem array from JS pairs and return its pointer + size.
 * Caller is responsible for amiga.freeMem(ptr, size) — or use the
 * `withTags` ergonomic helper.
 *
 * @param {Array<[number, number]>} pairs
 * @returns {{ptr: number, size: number}}
 */
function makeTags(pairs) {
  return {
    ptr: globalThis.amiga.makeTags(pairs),
    size: (pairs.length + 1) * 8,
  };
}

/**
 * Allocate a TagItem array, run fn(ptr), free it whether or not fn
 * throws.
 *
 * @template T
 * @param {Array<[number, number]>} pairs
 * @param {(ptr: number) => T} fn
 * @returns {T}
 */
function withTags(pairs, fn) {
  let { ptr, size } = makeTags(pairs);

  try {
    return fn(ptr);
  }

  finally {
    globalThis.amiga.freeMem(ptr, size);
  }
}


/* === structs/NewWindow.js === */
/* quickjs-master/amiga/ffi/structs/NewWindow.js
 *
 * Constructable wrapper around the legacy 48-byte struct NewWindow.
 * Used by Intuition.OpenWindow (the pre-tag-list API).
 *
 * Field offsets (intuition/intuition.h, 2-byte alignment):
 *   +0   LeftEdge (WORD)
 *   +2   TopEdge (WORD)
 *   +4   Width (WORD)
 *   +6   Height (WORD)
 *   +8   DetailPen (UBYTE)
 *   +9   BlockPen (UBYTE)
 *  +10   IDCMPFlags (ULONG)
 *  +14   Flags (ULONG)
 *  +18   FirstGadget (Gadget*)
 *  +22   CheckMark (Image*)
 *  +26   Title (STRPTR)
 *  +30   Screen (Screen*)
 *  +34   BitMap (BitMap*)
 *  +38   MinWidth (WORD)
 *  +40   MinHeight (WORD)
 *  +42   MaxWidth (UWORD)
 *  +44   MaxHeight (UWORD)
 *  +46   Type (UWORD)
 *
 * The constructor accepts an init object with camelCase field names.
 * If `title` is a string, the wrapper allocates the C string, pokes
 * the pointer at +26, and frees it on .free().
 */


class NewWindow extends Struct {
  /** @type {number} */
  static SIZE = 48;

  /**
   * REPL help text — a human-readable constructor signature.
   *
   * @returns {string}
   */
  static get signature() {
    return `NewWindow(initOrPtr?)
where:
  initOrPtr? - one of:
    - number: wrap an existing NewWindow* pointer (no allocation).
    - object: allocate a fresh 48-byte struct and populate fields.
    - omitted: allocate a zeroed 48-byte struct with sensible
               defaults (detailPen=0xFF, blockPen=0xFF, type=1).

Init-object fields (all optional, camelCase):
  left, top             {number} placement on screen
  width, height         {number}
  detailPen, blockPen   {number} title-bar pens (default 0xFF = -1)
  idcmp                 {number} IDCMP_* bitmask
  flags                 {number} WFLG_* bitmask
  title                 {string|number} JS string (owned copy) or
                                 caller-managed STRPTR
  minWidth, minHeight   {number}
  maxWidth, maxHeight   {number}
  type                  {number} 1=WBENCHSCREEN, 0xF=CUSTOMSCREEN

Methods:
  free()  - frees struct + any owned title string (idempotent).

Typical use:
  let nw = new NewWindow({
    width: 320, height: 200, title: 'Hi',
    flags: Intuition.consts.WFLG_CLOSEGADGET | WFLG_ACTIVATE,
    idcmp: Intuition.consts.IDCMP_CLOSEWINDOW,
  });
  let win = Intuition.OpenWindow(nw);
  try { ... } finally { win.close(); nw.free(); }`;
  }

  /**
   * @param {object|number} [initOrPtr]
   *   If a number: wrap an existing NewWindow pointer (no
   *   allocation). If an object: allocate a fresh struct, populate
   *   fields. Fields:
   *     left, top, width, height, detailPen, blockPen, idcmp, flags,
   *     title (string or pointer), minWidth, minHeight, maxWidth,
   *     maxHeight, type (1=WBENCHSCREEN, 0xF=CUSTOMSCREEN).
   */
  constructor(initOrPtr) {
    if (typeof initOrPtr === 'number') {
      super(initOrPtr);
      this._titleAlloc = null;
      return;
    }

    super();
    this._titleAlloc = null;

    /* DetailPen / BlockPen default to 0xFF (-1) per the C convention. */
    this.write8(8, 0xFF);
    this.write8(9, 0xFF);

    /* Type default = WBENCHSCREEN (1) */
    this.write16(46, 1);

    if (!initOrPtr) {
      return;
    }

    let i = initOrPtr;

    if (i.left      !== undefined) this.left      = i.left;
    if (i.top       !== undefined) this.top       = i.top;
    if (i.width     !== undefined) this.width     = i.width;
    if (i.height    !== undefined) this.height    = i.height;
    if (i.detailPen !== undefined) this.write8(8, i.detailPen);
    if (i.blockPen  !== undefined) this.write8(9, i.blockPen);
    if (i.idcmp     !== undefined) this.idcmp     = i.idcmp;
    if (i.flags     !== undefined) this.flags     = i.flags;
    if (i.title     !== undefined) this.title     = i.title;
    if (i.minWidth  !== undefined) this.write16(38, i.minWidth);
    if (i.minHeight !== undefined) this.write16(40, i.minHeight);
    if (i.maxWidth  !== undefined) this.write16(42, i.maxWidth);
    if (i.maxHeight !== undefined) this.write16(44, i.maxHeight);
    if (i.type      !== undefined) this.write16(46, i.type);
  }

  /**
   * Frees the underlying memory AND any owned title string.
   *
   * @returns {undefined}
   */
  free() {
    if (this._titleAlloc) {
      globalThis.amiga.freeMem(
        this._titleAlloc.ptr,
        this._titleAlloc.size
      );
      this._titleAlloc = null;
    }

    super.free();
  }

  get left()      { return this.read16(0); }
  set left(v)     { this.write16(0, v); }

  get top()       { return this.read16(2); }
  set top(v)      { this.write16(2, v); }

  get width()     { return this.read16(4); }
  set width(v)    { this.write16(4, v); }

  get height()    { return this.read16(6); }
  set height(v)   { this.write16(6, v); }

  get idcmp()     { return this.read32(10); }
  set idcmp(v)    { this.write32(10, v | 0); }

  get flags()     { return this.read32(14); }
  set flags(v)    { this.write32(14, v | 0); }

  /**
   * Title field. Set with a string to allocate + own; set with a
   * number to use a caller-managed pointer (no auto-free).
   */
  set title(value) {
    if (this._titleAlloc) {
      globalThis.amiga.freeMem(
        this._titleAlloc.ptr,
        this._titleAlloc.size
      );
      this._titleAlloc = null;
    }

    if (value === null || value === undefined || value === 0) {
      this.write32(26, 0);
      return;
    }

    if (typeof value === 'string') {
      let bytes = value.length + 1;
      let strPtr = globalThis.amiga.allocMem(bytes);

      if (!strPtr) {
        throw new Error('NewWindow.title: allocMem failed');
      }

      globalThis.amiga.pokeString(strPtr, value);
      this.write32(26, strPtr);
      this._titleAlloc = { ptr: strPtr, size: bytes };
      return;
    }

    /* number / pointer */
    this.write32(26, ptrOf(value));
  }

  get title() {
    let p = this.read32(26);

    return p ? globalThis.amiga.peekString(p, 256) : null;
  }
}


/* === structs/Window.js === */
/* quickjs-master/amiga/ffi/structs/Window.js
 *
 * Wraps a struct Window pointer returned by Intuition.OpenWindow*.
 *
 * Field offsets (intuition/intuition.h, 2-byte alignment):
 *   +0   NextWindow (4)
 *   +4   LeftEdge (2), +6 TopEdge (2), +8 Width (2), +10 Height (2)
 *  +12   MouseY (2), +14 MouseX (2)
 *  +16   MinWidth, +18 MinHeight, +20 MaxWidth, +22 MaxHeight
 *  +24   Flags (4)
 *  +28   MenuStrip (4)
 *  +32   Title (STRPTR)
 *  +36   FirstRequest (4)
 *  +40   DMRequest (4)
 *  +44   ReqCount (2)
 *  +46   WScreen (Screen*, 4)
 *  +50   RPort (RastPort*, 4)
 *  +54   BorderLeft, BorderTop, BorderRight, BorderBottom (4 × BYTE)
 *  +58   BorderRPort (4)
 *  +62   FirstGadget (4)
 *  +66   Parent, +70 Descendant (4 each)
 *  +74   Pointer (4)
 *  +78   PtrHeight, PtrWidth, XOffset, YOffset (4 × BYTE)
 *  +82   IDCMPFlags (4)
 *  +86   UserPort (MsgPort*, 4)
 */


class Window extends Struct {
  /* SIZE not exposed — Window is allocated by Intuition. */

  /**
   * REPL help text — a human-readable constructor signature.
   *
   * @returns {string}
   */
  static get signature() {
    return `Window(ptr)
where:
  ptr - REQUIRED: an existing struct Window pointer returned by
        Intuition.OpenWindow / Intuition.OpenWindowTags /
        Intuition.OpenWindowTagList. You cannot allocate a Window
        from scratch — only Intuition may.

Fields (read-only getters): leftEdge, topEdge, width, height, title,
  screen, rastPort, userPort.

Methods:
  close()      - Intuition.CloseWindow(this). Idempotent, zeroes ptr.
  move(dx,dy)  - MoveWindow
  toFront()/toBack() - WindowToFront/WindowToBack
  messages()   - generator yielding IntuiMessage instances; see
                 Intuition.consts.IDCMP_* for flags.`;
  }

  /** @returns {number} */
  get leftEdge() { return this.read16(4); }

  /** @returns {number} */
  get topEdge()  { return this.read16(6); }

  /** @returns {number} */
  get width()    { return this.read16(8); }

  /** @returns {number} */
  get height()   { return this.read16(10); }

  /** @returns {string|null} */
  get title() {
    let p = this.read32(32);

    return p ? globalThis.amiga.peekString(p, 256) : null;
  }

  /** @returns {Screen|null} */
  get screen() {
    let p = this.read32(46);

    return p ? new Screen(p) : null;
  }

  /** @returns {RastPort|null} */
  get rastPort() {
    let p = this.read32(50);

    return p ? new RastPort(p) : null;
  }

  /** @returns {MsgPort|null} */
  get userPort() {
    let p = this.read32(86);

    return p ? new MsgPort(p) : null;
  }

  /**
   * Close this window. Idempotent — safe to call multiple times.
   * After: this.ptr = 0 and further methods will throw.
   *
   * @returns {undefined}
   */
  close() {
    if (!this.ptr) {
      return;
    }

    globalThis.amiga.Intuition.CloseWindow(this);
    this.ptr = 0;
  }

  /**
   * Move this window by (dx, dy) on its screen.
   *
   * @param {number} dx
   * @param {number} dy
   */
  move(dx, dy) {
    return globalThis.amiga.Intuition.MoveWindow(this, dx, dy);
  }

  /**
   * Bring this window to the front of its screen.
   */
  toFront() {
    return globalThis.amiga.Intuition.WindowToFront(this);
  }

  /**
   * Send to the back.
   */
  toBack() {
    return globalThis.amiga.Intuition.WindowToBack(this);
  }

  /**
   * Yields IntuiMessages until the window closes or the consumer
   * breaks. Each iteration:
   *   1. Wait()s on the UserPort's signal bit
   *   2. Drains all queued messages via GetMsg
   *   3. Yields each one
   *   4. Replies to the message in the iterator's finally block
   *      (so a consumer that breaks mid-loop still cleans up the
   *      most recent message)
   *
   * @example
   * for (let msg of win.messages()) {
   *   if (msg.class === Intuition.consts.IDCMP_CLOSEWINDOW) break;
   * }
   *
   * @yields {IntuiMessage}
   */
  * messages() {
    let port = this.userPort;

    if (!port) {
      return;
    }

    let sigMask = port.sigMask;
    let Exec = globalThis.amiga.Exec;

    while (this.ptr) {
      Exec.Wait(sigMask);

      let raw;

      while ((raw = Exec.GetMsg(port)) !== 0) {
        let msg = new IntuiMessage(raw);

        try {
          yield msg;
        }

        finally {
          Exec.ReplyMsg(msg);
        }
      }
    }
  }
}


/* === Exec.js === */
/* quickjs-master/amiga/ffi/Exec.js
 *
 * Wrapper for exec.library. ROM-resident; always available.
 *
 * Pilot scope: ~30 LVO methods covering memory, message ports,
 * signals, library/device opens, and IO-request basics. The full
 * FFI table at amiga.exec.lvo has all 115; users who want the rest
 * can call them via amiga.call directly until generated.
 */


/**
 * Wrapper for exec.library — memory, tasks, signals, message ports,
 * library/device management.
 */
class Exec extends LibraryBase {
  /** @type {string} */
  static libraryName    = 'exec.library';

  /** @type {number} */
  static libraryVersion = 0;

  /** @type {Object<string, number>} */
  static lvo            = globalThis.amiga.exec.lvo;

  /**
   * Memory flags for AllocMem/AllocVec. Cases coerce to their
   * numeric value via Symbol.toPrimitive.
   *
   * @example
   * Exec.AllocMem(64,
   *   Exec.consts.MEMF_PUBLIC | Exec.consts.MEMF_CLEAR);
   */
  static consts = class ExecConsts extends CEnumeration {
    static {
      ExecConsts.define('MEMF_ANY',        0x00000000);
      ExecConsts.define('MEMF_PUBLIC',     0x00000001);
      ExecConsts.define('MEMF_CHIP',       0x00000002);
      ExecConsts.define('MEMF_FAST',       0x00000004);
      ExecConsts.define('MEMF_LOCAL',      0x00000100);
      ExecConsts.define('MEMF_24BITDMA',   0x00000200);
      ExecConsts.define('MEMF_KICK',       0x00000400);
      ExecConsts.define('MEMF_CLEAR',      0x00010000);
      ExecConsts.define('MEMF_LARGEST',    0x00020000);
      ExecConsts.define('MEMF_REVERSE',    0x00080000);
      ExecConsts.define('MEMF_TOTAL',      0x00040000);
      ExecConsts.define('MEMF_NO_EXPUNGE', 0x80000000);
    }
  };

  /** @returns {number} library base, or 0 on failure */
  static OpenLibrary(name, version) {
    return globalThis.amiga.openLibrary(name, version | 0);
  }

  /** @param {number} lib library base */
  static CloseLibrary(lib) {
    return globalThis.amiga.closeLibrary(ptrOf(lib));
  }

  /** AllocMem(size, requirements) — d0=size, d1=requirements */
  static AllocMem(size, flags) {
    return this.call(this.lvo.AllocMem,
      { d0: size | 0, d1: flags | 0 });
  }

  /** FreeMem(memoryBlock, size) — a1=memoryBlock, d0=size */
  static FreeMem(ptr, size) {
    return this.call(this.lvo.FreeMem,
      { a1: ptrOf(ptr), d0: size | 0 });
  }

  /** AllocVec(size, requirements) — d0=size, d1=requirements */
  static AllocVec(size, flags) {
    return this.call(this.lvo.AllocVec,
      { d0: size | 0, d1: flags | 0 });
  }

  /** FreeVec(memoryBlock) — a1=memoryBlock */
  static FreeVec(ptr) {
    return this.call(this.lvo.FreeVec, { a1: ptrOf(ptr) });
  }

  /** FindTask(name) — a1=name (NULL = current task). Returns task ptr. */
  static FindTask(name) {
    return this.call(this.lvo.FindTask, { a1: ptrOf(name) });
  }

  /** Wait(signalSet) — d0=signalSet. Returns received signals. */
  static Wait(sigMask) {
    return this.call(this.lvo.Wait, { d0: sigMask | 0 });
  }

  /** Signal(task, signals) — a1=task, d0=signals */
  static Signal(task, sigs) {
    return this.call(this.lvo.Signal,
      { a1: ptrOf(task), d0: sigs | 0 });
  }

  /** AllocSignal(signalNum) — d0=signalNum (-1 for any). Returns bit#. */
  static AllocSignal(num) {
    return this.call(this.lvo.AllocSignal, { d0: num | 0 });
  }

  /** FreeSignal(signalNum) — d0=signalNum */
  static FreeSignal(num) {
    return this.call(this.lvo.FreeSignal, { d0: num | 0 });
  }

  /** GetMsg(port) — a0=port. Returns message ptr or 0. */
  static GetMsg(port) {
    return this.call(this.lvo.GetMsg, { a0: ptrOf(port) });
  }

  /** PutMsg(port, message) — a0=port, a1=message */
  static PutMsg(port, msg) {
    return this.call(this.lvo.PutMsg,
      { a0: ptrOf(port), a1: ptrOf(msg) });
  }

  /** ReplyMsg(message) — a1=message */
  static ReplyMsg(msg) {
    return this.call(this.lvo.ReplyMsg, { a1: ptrOf(msg) });
  }

  /** WaitPort(port) — a0=port. Returns first message ptr (no remove). */
  static WaitPort(port) {
    return this.call(this.lvo.WaitPort, { a0: ptrOf(port) });
  }

  /** CreateMsgPort() — no args. Returns MsgPort* or 0. */
  static CreateMsgPort() {
    return this.call(this.lvo.CreateMsgPort, {});
  }

  /** DeleteMsgPort(port) — a0=port */
  static DeleteMsgPort(port) {
    return this.call(this.lvo.DeleteMsgPort, { a0: ptrOf(port) });
  }

  /** Forbid() — disable task switching */
  static Forbid()  { return this.call(this.lvo.Forbid,  {}); }

  /** Permit() — re-enable task switching */
  static Permit()  { return this.call(this.lvo.Permit,  {}); }

  /** Disable() — disable interrupts. PAIR with Enable(). */
  static Disable() { return this.call(this.lvo.Disable, {}); }

  /** Enable()  — re-enable interrupts */
  static Enable()  { return this.call(this.lvo.Enable,  {}); }

  /** OpenDevice(name, unit, ioRequest, flags) — a0/d0/a1/d1 */
  static OpenDevice(name, unit, ioRequest, flags) {
    return this.call(this.lvo.OpenDevice, {
      a0: ptrOf(name), d0: unit | 0,
      a1: ptrOf(ioRequest), d1: flags | 0,
    });
  }

  /** CloseDevice(ioRequest) — a1=ioRequest */
  static CloseDevice(ioReq) {
    return this.call(this.lvo.CloseDevice, { a1: ptrOf(ioReq) });
  }

  /** DoIO(ioRequest) — a1=ioRequest. Returns io_Error. */
  static DoIO(ioReq) {
    return this.call(this.lvo.DoIO, { a1: ptrOf(ioReq) });
  }

  /** SendIO(ioRequest) — a1=ioRequest */
  static SendIO(ioReq) {
    return this.call(this.lvo.SendIO, { a1: ptrOf(ioReq) });
  }

  /** CheckIO(ioRequest) — a1=ioRequest. Returns ptr if done, 0 if pending. */
  static CheckIO(ioReq) {
    return this.call(this.lvo.CheckIO, { a1: ptrOf(ioReq) });
  }

  /** WaitIO(ioRequest) — a1=ioRequest. Returns io_Error. */
  static WaitIO(ioReq) {
    return this.call(this.lvo.WaitIO, { a1: ptrOf(ioReq) });
  }

  /** AbortIO(ioRequest) — a1=ioRequest */
  static AbortIO(ioReq) {
    return this.call(this.lvo.AbortIO, { a1: ptrOf(ioReq) });
  }

  /** CopyMem(source, dest, size) — a0/a1/d0 */
  static CopyMem(src, dst, size) {
    return this.call(this.lvo.CopyMem, {
      a0: ptrOf(src), a1: ptrOf(dst), d0: size | 0,
    });
  }

  /** AvailMem(requirements) — d1=requirements */
  static AvailMem(flags) {
    return this.call(this.lvo.AvailMem, { d1: flags | 0 });
  }
}


/* === Dos.js === */
/* quickjs-master/amiga/ffi/Dos.js
 *
 * Wrapper for dos.library. Pilot scope: ~20 of 161 LVOs covering
 * file I/O, locking, dates, exec.
 */


class Dos extends LibraryBase {
  /** @type {string} */
  static libraryName = 'dos.library';

  /** @type {number} */
  static libraryVersion = 39;

  /** @type {Object<string, number>} */
  static lvo = globalThis.amiga.dos.lvo;

  /**
   * Common dos.library mode flags and seek origins.
   */
  static consts = class DosConsts extends CEnumeration {
    static {
      DosConsts.define('MODE_OLDFILE',     1005);
      DosConsts.define('MODE_NEWFILE',     1006);
      DosConsts.define('MODE_READWRITE',   1004);
      DosConsts.define('OFFSET_BEGINNING', -1);
      DosConsts.define('OFFSET_CURRENT',    0);
      DosConsts.define('OFFSET_END',        1);
      DosConsts.define('ACCESS_READ',      -2);
      DosConsts.define('ACCESS_WRITE',     -1);
    }
  };

  /**
   * Open(name, accessMode) — d1=name, d2=accessMode. Returns BPTR.
   * Accepts a JS string for `name` (allocates + frees a C copy).
   */
  static Open(name, accessMode) {
    let namePtr = ptrOf(name);
    let bytes = 0;

    if (typeof name === 'string') {
      bytes = name.length + 1;
      namePtr = globalThis.amiga.allocMem(bytes);
      globalThis.amiga.pokeString(namePtr, name);
    }

    try {
      return this.call(this.lvo.Open, {
        d1: namePtr, d2: accessMode | 0,
      });
    }

    finally {
      if (bytes) globalThis.amiga.freeMem(namePtr, bytes);
    }
  }

  static Close(file)  { return this.call(this.lvo.Close, { d1: file | 0 }); }
  static Input()      { return this.call(this.lvo.Input,  {}); }
  static Output()     { return this.call(this.lvo.Output, {}); }
  static IoErr()      { return this.call(this.lvo.IoErr,  {}); }

  static Read(file, buffer, length) {
    return this.call(this.lvo.Read, {
      d1: file | 0, d2: ptrOf(buffer), d3: length | 0,
    });
  }

  static Write(file, buffer, length) {
    return this.call(this.lvo.Write, {
      d1: file | 0, d2: ptrOf(buffer), d3: length | 0,
    });
  }

  static Seek(file, position, mode) {
    return this.call(this.lvo.Seek, {
      d1: file | 0, d2: position | 0, d3: mode | 0,
    });
  }

  /**
   * Lock(name, accessMode) — accepts a JS string name.
   */
  static Lock(name, accessMode) {
    let namePtr = ptrOf(name);
    let bytes = 0;

    if (typeof name === 'string') {
      bytes = name.length + 1;
      namePtr = globalThis.amiga.allocMem(bytes);
      globalThis.amiga.pokeString(namePtr, name);
    }

    try {
      return this.call(this.lvo.Lock, {
        d1: namePtr, d2: accessMode | 0,
      });
    }

    finally {
      if (bytes) globalThis.amiga.freeMem(namePtr, bytes);
    }
  }

  static UnLock(lock) { return this.call(this.lvo.UnLock, { d1: lock | 0 }); }

  static DateStamp(ds) {
    return this.call(this.lvo.DateStamp, { d1: ptrOf(ds) });
  }

  static Delay(ticks) {
    return this.call(this.lvo.Delay, { d1: ticks | 0 });
  }

  static SystemTagList(cmd, tags) {
    let cmdPtr = ptrOf(cmd);
    let bytes = 0;

    if (typeof cmd === 'string') {
      bytes = cmd.length + 1;
      cmdPtr = globalThis.amiga.allocMem(bytes);
      globalThis.amiga.pokeString(cmdPtr, cmd);
    }

    try {
      return this.call(this.lvo.SystemTagList, {
        d1: cmdPtr, d2: ptrOf(tags),
      });
    }

    finally {
      if (bytes) globalThis.amiga.freeMem(cmdPtr, bytes);
    }
  }
}


/* === Graphics.js === */
/* quickjs-master/amiga/ffi/Graphics.js
 *
 * Wrapper for graphics.library. Pilot scope: ~20 of 163 LVOs
 * covering pens, lines, fills, text, color.
 */


class Graphics extends LibraryBase {
  /** @type {string} */
  static libraryName = 'graphics.library';

  /** @type {number} */
  static libraryVersion = 39;

  /** @type {Object<string, number>} */
  static lvo = globalThis.amiga.graphics.lvo;

  /**
   * Drawing mode constants for SetDrMd.
   */
  static consts = class GraphicsConsts extends CEnumeration {
    static {
      GraphicsConsts.define('JAM1',       0x00);
      GraphicsConsts.define('JAM2',       0x01);
      GraphicsConsts.define('COMPLEMENT', 0x02);
      GraphicsConsts.define('INVERSVID',  0x04);
    }
  };

  /* ============================================================
   * Pen / drawing mode setters
   * ============================================================ */

  /**
   * Set the A (foreground) pen number on a RastPort.
   *
   * @param {RastPort|number} rport — RastPort wrapper or raw pointer
   * @param {number}          pen   — color index (0..ncolors-1)
   * @returns {number} previous A-pen value
   */
  static SetAPen(rport, pen) {
    return this.call(this.lvo.SetAPen,
      { a1: ptrOf(rport), d0: pen | 0 });
  }

  /**
   * Set the B (background) pen number on a RastPort.
   *
   * @param {RastPort|number} rport
   * @param {number}          pen
   * @returns {number} previous B-pen value
   */
  static SetBPen(rport, pen) {
    return this.call(this.lvo.SetBPen,
      { a1: ptrOf(rport), d0: pen | 0 });
  }

  /**
   * Set the drawing mode on a RastPort. Use `Graphics.consts.JAM1`,
   * `JAM2`, `COMPLEMENT`, or `INVERSVID` (bits may be OR'd).
   *
   * @param {RastPort|number} rport
   * @param {number}          mode  — bitmask of JAM1/JAM2/COMPLEMENT/INVERSVID
   * @returns {number} previous DrMd value
   */
  static SetDrMd(rport, mode) {
    return this.call(this.lvo.SetDrMd,
      { a1: ptrOf(rport), d0: mode | 0 });
  }

  /* ============================================================
   * Cursor + lines
   * ============================================================ */

  /**
   * Move the RastPort pen to (x, y) without drawing.
   *
   * @param {RastPort|number} rport
   * @param {number}          x
   * @param {number}          y
   * @returns {undefined}
   */
  static Move(rport, x, y) {
    return this.call(this.lvo.Move, {
      a1: ptrOf(rport), d0: x | 0, d1: y | 0,
    });
  }

  /**
   * Draw a line from the current pen position to (x, y).
   *
   * @param {RastPort|number} rport
   * @param {number}          x
   * @param {number}          y
   * @returns {undefined}
   */
  static Draw(rport, x, y) {
    return this.call(this.lvo.Draw, {
      a1: ptrOf(rport), d0: x | 0, d1: y | 0,
    });
  }

  /* ============================================================
   * Fills
   * ============================================================ */

  /**
   * Fill a rectangle (inclusive) with the current A-pen.
   *
   * @param {RastPort|number} rport
   * @param {number}          x1
   * @param {number}          y1
   * @param {number}          x2
   * @param {number}          y2
   * @returns {undefined}
   */
  static RectFill(rport, x1, y1, x2, y2) {
    return this.call(this.lvo.RectFill, {
      a1: ptrOf(rport),
      d0: x1 | 0, d1: y1 | 0,
      d2: x2 | 0, d3: y2 | 0,
    });
  }

  /**
   * Fill a raw memory block with zeroes using the blitter.
   *
   * @param {number} memBlock — aligned ptr
   * @param {number} count    — bytes to clear
   * @param {number} flags    — BLTCLEAR_* flags
   * @returns {undefined}
   */
  static BltClear(memBlock, count, flags) {
    return this.call(this.lvo.BltClear, {
      a1: ptrOf(memBlock), d0: count | 0, d1: flags | 0,
    });
  }

  /**
   * Set the area-fill pattern for RectFill/Flood. `pattern` is a
   * planar bitmap ptr (2^size lines tall). Set `pattern=0` to clear.
   *
   * @param {RastPort|number} rport
   * @param {number}          pattern — ptr to pattern words, or 0
   * @param {number}          size    — power-of-2 line count (e.g. 1=2px, 4=16px)
   * @returns {undefined}
   */
  static SetAfPt(rport, pattern, size) {
    return this.call(this.lvo.SetAfPt, {
      a1: ptrOf(rport), a0: ptrOf(pattern), d0: size | 0,
    });
  }

  /* ============================================================
   * Text
   * ============================================================ */

  /**
   * Render `length` characters from `str` at the current pen
   * position, advancing the cursor.
   *
   * @param {RastPort|number} rport
   * @param {number}          str    — ptr to char data (not null-terminated need)
   * @param {number}          length — chars to render
   * @returns {undefined}
   */
  static Text(rport, str, length) {
    return this.call(this.lvo.Text, {
      a1: ptrOf(rport), a0: ptrOf(str), d0: length | 0,
    });
  }

  /**
   * Return the pixel width of `length` chars of `str` in the
   * RastPort's current font.
   *
   * @param {RastPort|number} rport
   * @param {number}          str
   * @param {number}          length
   * @returns {number} pixel width
   */
  static TextLength(rport, str, length) {
    return this.call(this.lvo.TextLength, {
      a1: ptrOf(rport), a0: ptrOf(str), d0: length | 0,
    });
  }

  /**
   * Install a font (TextFont ptr) on the RastPort.
   *
   * @param {RastPort|number} rport
   * @param {number}          font — TextFont ptr from OpenFont
   * @returns {number} previous font ptr
   */
  static SetFont(rport, font) {
    return this.call(this.lvo.SetFont, {
      a1: ptrOf(rport), a0: ptrOf(font),
    });
  }

  /* ============================================================
   * Pixels
   * ============================================================ */

  /**
   * Read the pen number at (x, y). Returns -1 if out of bounds.
   *
   * @param {RastPort|number} rport
   * @param {number}          x
   * @param {number}          y
   * @returns {number}
   */
  static ReadPixel(rport, x, y) {
    return this.call(this.lvo.ReadPixel, {
      a1: ptrOf(rport), d0: x | 0, d1: y | 0,
    });
  }

  /**
   * Plot a pixel at (x, y) using the current A-pen.
   *
   * @param {RastPort|number} rport
   * @param {number}          x
   * @param {number}          y
   * @returns {number} 0 on success, -1 if out of bounds
   */
  static WritePixel(rport, x, y) {
    return this.call(this.lvo.WritePixel, {
      a1: ptrOf(rport), d0: x | 0, d1: y | 0,
    });
  }

  /* ============================================================
   * Color map
   * ============================================================ */

  /**
   * Bulk-load `count` 12-bit RGB values (starting at pen 0) into a
   * ViewPort's ColorMap.
   *
   * @param {number} viewPort — ViewPort ptr
   * @param {number} colors   — ptr to UWORDs (0x0RGB each)
   * @param {number} count
   * @returns {undefined}
   */
  static LoadRGB4(viewPort, colors, count) {
    return this.call(this.lvo.LoadRGB4, {
      a0: ptrOf(viewPort), a1: ptrOf(colors), d0: count | 0,
    });
  }

  /**
   * Set one color-map entry to a 12-bit RGB (each 0..15).
   *
   * @param {number} viewPort
   * @param {number} index — pen number
   * @param {number} r — 0..15
   * @param {number} g — 0..15
   * @param {number} b — 0..15
   * @returns {undefined}
   */
  static SetRGB4(viewPort, index, r, g, b) {
    return this.call(this.lvo.SetRGB4, {
      a0: ptrOf(viewPort),
      d0: index | 0, d1: r | 0, d2: g | 0, d3: b | 0,
    });
  }

  /**
   * Read a 12-bit packed RGB value from a ColorMap entry.
   *
   * @param {number} colorMap
   * @param {number} entry — pen number
   * @returns {number} 0x0RGB value
   */
  static GetRGB4(colorMap, entry) {
    return this.call(this.lvo.GetRGB4,
      { a0: ptrOf(colorMap), d0: entry | 0 });
  }

  /* ============================================================
   * Misc
   * ============================================================ */

  /** Block until vertical blank (top of frame). @returns {undefined} */
  static WaitTOF()  { return this.call(this.lvo.WaitTOF,  {}); }

  /** Block until pending blitter operations finish. @returns {undefined} */
  static WaitBlit() { return this.call(this.lvo.WaitBlit, {}); }
}


/* === GadTools.js === */
/* quickjs-master/amiga/ffi/GadTools.js
 *
 * Wrapper for gadtools.library. All 21 LVOs covered. The C-side
 * names use a `GT_` prefix for some functions; we strip it in the
 * JS form (GadTools.GetIMsg not GadTools.GT_GetIMsg). Raw form
 * remains accessible via amiga.gadtools.lvo.GT_* for anyone who
 * wants it.
 */


class GadTools extends LibraryBase {
  /** @type {string} */
  static libraryName = 'gadtools.library';

  /** @type {number} */
  static libraryVersion = 39;

  /** @type {Object<string, number>} */
  static lvo = globalThis.amiga.gadtools.lvo;

  /**
   * Gadget kinds (CreateGadgetA's first arg) and selected GT_/GTLV_/
   * GTCB_/GTST_/GTIN_ tag IDs.
   */
  static consts = class GadToolsConsts extends CEnumeration {
    static {
      /* Gadget kinds */
      GadToolsConsts.define('GENERIC_KIND',    0);
      GadToolsConsts.define('BUTTON_KIND',     1);
      GadToolsConsts.define('CHECKBOX_KIND',   2);
      GadToolsConsts.define('INTEGER_KIND',    3);
      GadToolsConsts.define('LISTVIEW_KIND',   4);
      GadToolsConsts.define('MX_KIND',         5);
      GadToolsConsts.define('NUMBER_KIND',     6);
      GadToolsConsts.define('CYCLE_KIND',      7);
      GadToolsConsts.define('PALETTE_KIND',    8);
      GadToolsConsts.define('SCROLLER_KIND',   9);
      GadToolsConsts.define('SLIDER_KIND',    11);
      GadToolsConsts.define('STRING_KIND',    12);
      GadToolsConsts.define('TEXT_KIND',      13);

      /* Common GadTools tag constants. Raw NDK names use the
       * `GT_` / `GTLV_` / etc. prefixes; we keep them here verbatim
       * on the JS side because the prefix tells you which gadget
       * kind the tag is for (it's an attribute prefix, not a
       * library prefix). */
      GadToolsConsts.define('GT_Underscore', 0x80000036);
      GadToolsConsts.define('GTCB_Checked',  0x800000B4);
      GadToolsConsts.define('GTLV_Selected', 0x80000068);
      GadToolsConsts.define('GTLV_Labels',   0x80000067);
      GadToolsConsts.define('GTST_String',   0x80000140);
      GadToolsConsts.define('GTIN_Number',   0x80000180);
    }
  };

  /* === Methods (GT_ library prefix stripped where applicable) === */

  static CreateContext(glistPtrPtr) {
    return this.call(this.lvo.CreateContext, { a0: ptrOf(glistPtrPtr) });
  }

  /**
   * CreateGadgetA(kind, prevGadget, newGadgetTemplate, tagList)
   * — d0 = kind, a0 = prevGadget, a1 = newGadget, a2 = tagList
   */
  static CreateGadgetA(kind, prev, ng, tagList) {
    return this.call(this.lvo.CreateGadgetA, {
      d0: kind | 0,
      a0: ptrOf(prev),
      a1: ptrOf(ng),
      a2: ptrOf(tagList),
    });
  }

  static CreateGadgetTags(kind, prev, ng, pairs) {
    let tags = globalThis.amiga.makeTags(pairs);
    let bytes = (pairs.length + 1) * 8;

    try {
      return this.CreateGadgetA(kind, prev, ng, tags);
    }

    finally {
      globalThis.amiga.freeMem(tags, bytes);
    }
  }

  static FreeGadgets(gad) {
    return this.call(this.lvo.FreeGadgets, { a0: ptrOf(gad) });
  }

  static SetGadgetAttrsA(gad, win, req, tagList) {
    return this.call(this.lvo.GT_SetGadgetAttrsA, {
      a0: ptrOf(gad), a1: ptrOf(win),
      a2: ptrOf(req), a3: ptrOf(tagList),
    });
  }

  static SetGadgetAttrsTags(gad, win, req, pairs) {
    let tags = globalThis.amiga.makeTags(pairs);
    let bytes = (pairs.length + 1) * 8;

    try {
      return this.SetGadgetAttrsA(gad, win, req, tags);
    }

    finally {
      globalThis.amiga.freeMem(tags, bytes);
    }
  }

  static GetGadgetAttrsA(gad, win, req, tagList) {
    return this.call(this.lvo.GT_GetGadgetAttrsA, {
      a0: ptrOf(gad), a1: ptrOf(win),
      a2: ptrOf(req), a3: ptrOf(tagList),
    });
  }

  static CreateMenusA(newMenu, tagList) {
    return this.call(this.lvo.CreateMenusA, {
      a0: ptrOf(newMenu), a1: ptrOf(tagList),
    });
  }

  static FreeMenus(menu) {
    return this.call(this.lvo.FreeMenus, { a0: ptrOf(menu) });
  }

  static LayoutMenuItemsA(item, vi, tagList) {
    return this.call(this.lvo.LayoutMenuItemsA, {
      a0: ptrOf(item), a1: ptrOf(vi), a2: ptrOf(tagList),
    });
  }

  static LayoutMenusA(menu, vi, tagList) {
    return this.call(this.lvo.LayoutMenusA, {
      a0: ptrOf(menu), a1: ptrOf(vi), a2: ptrOf(tagList),
    });
  }

  static GetIMsg(port) {
    return this.call(this.lvo.GT_GetIMsg, { a0: ptrOf(port) });
  }

  static ReplyIMsg(msg) {
    return this.call(this.lvo.GT_ReplyIMsg, { a1: ptrOf(msg) });
  }

  static RefreshWindow(window, requester) {
    return this.call(this.lvo.GT_RefreshWindow, {
      a0: ptrOf(window), a1: ptrOf(requester),
    });
  }

  static BeginRefresh(window) {
    return this.call(this.lvo.GT_BeginRefresh, { a0: ptrOf(window) });
  }

  static EndRefresh(window, complete) {
    return this.call(this.lvo.GT_EndRefresh, {
      a0: ptrOf(window), d0: complete ? 1 : 0,
    });
  }

  static FilterIMsg(msg) {
    return this.call(this.lvo.GT_FilterIMsg, { a1: ptrOf(msg) });
  }

  static PostFilterIMsg(msg) {
    return this.call(this.lvo.GT_PostFilterIMsg, { a1: ptrOf(msg) });
  }

  static DrawBevelBoxA(rport, x, y, w, h, tagList) {
    return this.call(this.lvo.DrawBevelBoxA, {
      a0: ptrOf(rport),
      d0: x | 0, d1: y | 0, d2: w | 0, d3: h | 0,
      a1: ptrOf(tagList),
    });
  }

  static GetVisualInfoA(screen, tagList) {
    return this.call(this.lvo.GetVisualInfoA, {
      a0: ptrOf(screen), a1: ptrOf(tagList),
    });
  }

  static FreeVisualInfo(vi) {
    return this.call(this.lvo.FreeVisualInfo, { a0: ptrOf(vi) });
  }
}


/* === Asl.js === */
/* quickjs-master/amiga/ffi/Asl.js
 *
 * Wrapper for asl.library. Covers the four standard requester types
 * (file, font, screenmode, arexx) via AllocAslRequest /
 * AslRequest / FreeAslRequest. Users can also pass a prepared tag
 * list through AslRequestA for finer control.
 *
 * The raw requester-return structs (FileRequester, FontRequester,
 * ScreenModeRequester, ArexxRequester) are accessed via their field
 * offsets on the returned pointer; full struct wrappers are pending
 * — for now the wrapper returns a struct-pointer + the common fields
 * you need (path, file, numArgs, argList).
 */


/**
 * asl.library — standard Amiga requester provider (file/font/
 * screenmode).
 */
class Asl extends LibraryBase {
  /** @type {string} */
  static libraryName = 'asl.library';

  /** @type {number} */
  static libraryVersion = 39;

  /** @type {Object<string, number>} */
  static lvo = globalThis.amiga.asl.lvo;

  /**
   * Requester-type selectors and the most-used ASL_* tag IDs.
   *
   *   ASL_FileRequest       = 0
   *   ASL_FontRequest       = 1
   *   ASL_ScreenModeRequest = 2
   *   ASL_ArexxRequest      = 3
   *
   * Tag IDs (ASLTAG_BASE = TAG_USER + 0x80000) common to all types:
   *   ASLFR_Window          = 0x80080018
   *   ASLFR_TitleText       = 0x80080001
   *   ASLFR_InitialDrawer   = 0x80080008
   *   ASLFR_InitialFile     = 0x8008000A
   *   ASLFR_InitialPattern  = 0x8008000B
   *   ASLFR_DoMultiSelect   = 0x80080020
   *   ASLFR_DoPatterns      = 0x80080021
   *   ASLFR_DoSaveMode      = 0x80080024
   *
   * ASLFO_* (font) and ASLSM_* (screenmode) follow the same scheme
   * with +0x10000 and +0x20000 bases respectively.
   */
  static consts = class AslConsts extends CEnumeration {
    static {
      AslConsts.define('ASL_FileRequest',       0);
      AslConsts.define('ASL_FontRequest',       1);
      AslConsts.define('ASL_ScreenModeRequest', 2);
      AslConsts.define('ASL_ArexxRequest',      3);

      /* File-request tags (the most-used subset). */
      AslConsts.define('ASLFR_Window',         0x80080018);
      AslConsts.define('ASLFR_TitleText',      0x80080001);
      AslConsts.define('ASLFR_InitialDrawer',  0x80080008);
      AslConsts.define('ASLFR_InitialFile',    0x8008000A);
      AslConsts.define('ASLFR_InitialPattern', 0x8008000B);
      AslConsts.define('ASLFR_DoMultiSelect',  0x80080020);
      AslConsts.define('ASLFR_DoPatterns',     0x80080021);
      AslConsts.define('ASLFR_DoSaveMode',     0x80080024);

      /* Font-request tags. */
      AslConsts.define('ASLFO_Window',         0x80090018);
      AslConsts.define('ASLFO_TitleText',      0x80090001);
      AslConsts.define('ASLFO_InitialName',    0x80090008);
      AslConsts.define('ASLFO_InitialSize',    0x80090009);

      /* Screenmode-request tags. */
      AslConsts.define('ASLSM_Window',         0x800A0018);
      AslConsts.define('ASLSM_TitleText',      0x800A0001);
    }
  };

  /**
   * AllocAslRequestA(type, tagList) — d0=type, a0=tagList. Returns
   * a Requester* pointer (opaque; fields read via offsets after
   * AslRequest).
   *
   * @param {number}      type    — ASL_FileRequest etc.
   * @param {number|null} tagList — prepared TagItem* or NULL
   * @returns {number} requester pointer (0 on failure)
   */
  static AllocAslRequestA(type, tagList) {
    return this.call(this.lvo.AllocAslRequestA, {
      d0: type | 0, a0: ptrOf(tagList),
    });
  }

  /**
   * Convenience over AllocAslRequestA — builds the TagItem array
   * from JS pairs and frees it after allocation.
   *
   * @param {number}                  type
   * @param {Array<[number, number]>} [pairs]
   * @returns {number} requester ptr
   */
  static AllocAslRequestTags(type, pairs) {
    let p = pairs || [];
    let tags = globalThis.amiga.makeTags(p);
    let bytes = (p.length + 1) * 8;

    try {
      return this.AllocAslRequestA(type, tags);
    }

    finally {
      globalThis.amiga.freeMem(tags, bytes);
    }
  }

  /**
   * FreeAslRequest(requester) — a0=requester.
   *
   * @param {number} requester
   * @returns {undefined}
   */
  static FreeAslRequest(requester) {
    return this.call(this.lvo.FreeAslRequest,
      { a0: ptrOf(requester) });
  }

  /**
   * AslRequest(requester, tagList) — a0=requester, a1=tagList.
   * Returns true (non-zero) if the user clicked OK; false if
   * cancelled or an error occurred.
   *
   * @param {number}      requester
   * @param {number|null} tagList
   * @returns {number} BOOL (0/1) as returned by asl.library
   */
  static AslRequest(requester, tagList) {
    return this.call(this.lvo.AslRequest, {
      a0: ptrOf(requester), a1: ptrOf(tagList),
    });
  }

  /**
   * Convenience — one call that allocates, runs the requester, and
   * frees cleanly. Returns a {ok, drawer, file, path} object for
   * file requesters, or {ok, requester} for other types.
   *
   * File-request layout (struct FileRequester after a successful
   * AslRequest):
   *   +4   fr_Drawer (STRPTR)
   *   +8   fr_File   (STRPTR)
   *   +16  fr_NumArgs (LONG)      — for multi-select
   *   +20  fr_ArgList (WBArg *)
   *
   * @param {Array<[number, number]>} pairs — ASLFR_* tag pairs
   * @returns {{ok: boolean, drawer: string|null, file: string|null, path: string|null, requester: number}}
   */
  static openFileRequest(pairs) {
    let req = this.AllocAslRequestTags(this.consts.ASL_FileRequest,
                                        pairs);

    if (!req) {
      return { ok: false, drawer: null, file: null, path: null,
               requester: 0 };
    }

    try {
      let ok = this.AslRequest(req, 0);

      if (!ok) {
        return { ok: false, drawer: null, file: null, path: null,
                 requester: req };
      }

      let drawerPtr = globalThis.amiga.peek32(req + 4);
      let filePtr   = globalThis.amiga.peek32(req + 8);

      let drawer = drawerPtr
        ? globalThis.amiga.peekString(drawerPtr, 512)
        : null;

      let file = filePtr
        ? globalThis.amiga.peekString(filePtr, 256)
        : null;

      let path = null;

      if (drawer !== null && file !== null) {
        let sep = '';

        if (drawer.length && !drawer.endsWith(':') &&
            !drawer.endsWith('/')) {
          sep = '/';
        }

        path = drawer + sep + file;
      }

      return { ok: true, drawer, file, path, requester: req };
    }

    finally {
      this.FreeAslRequest(req);
    }
  }
}


/* === Intuition.js === */
/* quickjs-master/amiga/ffi/Intuition.js
 *
 * Wrapper for intuition.library — windows, screens, gadgets, BOOPSI
 * imageclass, IDCMP messaging.
 *
 * Pilot scope: ~25 of 127 LVOs (the most-used surface). The
 * remaining are accessible via amiga.intuition.lvo + amiga.call.
 */


class Intuition extends LibraryBase {
  /** @type {string} */
  static libraryName = 'intuition.library';

  /** @type {number} */
  static libraryVersion = 39;

  /** @type {Object<string, number>} */
  static lvo = globalThis.amiga.intuition.lvo;

  /**
   * Window/Screen attribute tags, IDCMP flags, window flags, and
   * imageclass attributes from intuition.h. Cases coerce to their
   * numeric value via Symbol.toPrimitive — usable directly in tag
   * lists.
   */
  static consts = class IntuitionConsts extends CEnumeration {
    static {
      /* Window Attributes — WA_Dummy = TAG_USER + 99 = 0x80000063 */
      IntuitionConsts.define('WA_Left',         0x80000064);
      IntuitionConsts.define('WA_Top',          0x80000065);
      IntuitionConsts.define('WA_Width',        0x80000066);
      IntuitionConsts.define('WA_Height',       0x80000067);
      IntuitionConsts.define('WA_DetailPen',    0x80000068);
      IntuitionConsts.define('WA_BlockPen',     0x80000069);
      IntuitionConsts.define('WA_IDCMP',        0x8000006A);
      IntuitionConsts.define('WA_Flags',        0x8000006B);
      IntuitionConsts.define('WA_Gadgets',      0x8000006C);
      IntuitionConsts.define('WA_Title',        0x8000006E);
      IntuitionConsts.define('WA_ScreenTitle',  0x8000006F);
      IntuitionConsts.define('WA_CustomScreen', 0x80000070);
      IntuitionConsts.define('WA_MinWidth',     0x80000072);
      IntuitionConsts.define('WA_MinHeight',    0x80000073);
      IntuitionConsts.define('WA_MaxWidth',     0x80000074);
      IntuitionConsts.define('WA_MaxHeight',    0x80000075);
      IntuitionConsts.define('WA_PubScreenName',0x80000078);
      IntuitionConsts.define('WA_SimpleRefresh',0x80000079);
      IntuitionConsts.define('WA_SmartRefresh', 0x8000007A);
      IntuitionConsts.define('WA_BackFill',     0x8000007F);
      IntuitionConsts.define('WA_AutoAdjust',   0x80000083);

      /* Screen Attributes — SA_Dummy = TAG_USER + 32 = 0x80000020 */
      IntuitionConsts.define('SA_Left',     0x80000021);
      IntuitionConsts.define('SA_Top',      0x80000022);
      IntuitionConsts.define('SA_Width',    0x80000023);
      IntuitionConsts.define('SA_Height',   0x80000024);
      IntuitionConsts.define('SA_Depth',    0x80000025);
      IntuitionConsts.define('SA_Title',    0x80000028);
      IntuitionConsts.define('SA_Type',     0x8000002D);

      /* IA_ tags — IA_Dummy = TAG_USER + 0x20000 = 0x80020000 */
      IntuitionConsts.define('IA_Left',      0x80020001);
      IntuitionConsts.define('IA_Top',       0x80020002);
      IntuitionConsts.define('IA_Width',     0x80020003);
      IntuitionConsts.define('IA_Height',    0x80020004);
      IntuitionConsts.define('IA_FGPen',     0x80020005);
      IntuitionConsts.define('IA_BGPen',     0x80020006);
      IntuitionConsts.define('IA_Recessed',  0x80020015);
      IntuitionConsts.define('IA_FrameType', 0x8002001B);

      /* IDCMP flags */
      IntuitionConsts.define('IDCMP_SIZEVERIFY',    0x00000001);
      IntuitionConsts.define('IDCMP_NEWSIZE',       0x00000002);
      IntuitionConsts.define('IDCMP_REFRESHWINDOW', 0x00000004);
      IntuitionConsts.define('IDCMP_MOUSEBUTTONS',  0x00000008);
      IntuitionConsts.define('IDCMP_MOUSEMOVE',     0x00000010);
      IntuitionConsts.define('IDCMP_GADGETDOWN',    0x00000020);
      IntuitionConsts.define('IDCMP_GADGETUP',      0x00000040);
      IntuitionConsts.define('IDCMP_MENUPICK',      0x00000100);
      IntuitionConsts.define('IDCMP_CLOSEWINDOW',   0x00000200);
      IntuitionConsts.define('IDCMP_RAWKEY',        0x00000400);
      IntuitionConsts.define('IDCMP_VANILLAKEY',    0x00200000);

      /* WFLG — window flags (WA_Flags value) */
      IntuitionConsts.define('WFLG_SIZEGADGET',  0x00000001);
      IntuitionConsts.define('WFLG_DRAGBAR',     0x00000002);
      IntuitionConsts.define('WFLG_DEPTHGADGET', 0x00000004);
      IntuitionConsts.define('WFLG_CLOSEGADGET', 0x00000008);
      IntuitionConsts.define('WFLG_BACKDROP',    0x00000100);
      IntuitionConsts.define('WFLG_REPORTMOUSE', 0x00000200);
      IntuitionConsts.define('WFLG_BORDERLESS',  0x00000800);
      IntuitionConsts.define('WFLG_ACTIVATE',    0x00001000);

      /* Screen types (NewWindow.Type) */
      IntuitionConsts.define('WBENCHSCREEN', 0x0001);
      IntuitionConsts.define('CUSTOMSCREEN', 0x000F);
    }
  };

  /* ============================================================
   * Window lifecycle
   * ============================================================ */

  /**
   * Open a window using the legacy NewWindow struct.
   *
   * @param {NewWindow|number} newWindow
   * @returns {Window|null}
   */
  static OpenWindow(newWindow) {
    let raw = this.call(this.lvo.OpenWindow, { a0: ptrOf(newWindow) });

    return raw ? new Window(raw) : null;
  }

  /**
   * Faithful 1:1 wrapper for OpenWindowTagList.
   *
   * @param {NewWindow|number|null} newWindow
   * @param {number|null} tagList
   * @returns {Window|null}
   */
  static OpenWindowTagList(newWindow, tagList) {
    let raw = this.call(
      this.lvo.OpenWindowTagList,
      { a0: ptrOf(newWindow), a1: ptrOf(tagList) }
    );

    return raw ? new Window(raw) : null;
  }

  /**
   * Convenience over OpenWindowTagList — accepts JS [tag, data] pairs,
   * builds and frees the TagItem array internally.
   *
   * @param {Array<[number, number]>} pairs
   * @returns {Window|null}
   */
  static OpenWindowTags(pairs) {
    let tags = globalThis.amiga.makeTags(pairs);
    let bytes = (pairs.length + 1) * 8;

    try {
      return this.OpenWindowTagList(null, tags);
    }

    finally {
      globalThis.amiga.freeMem(tags, bytes);
    }
  }

  /**
   * Close a window. Pair with every Open*.
   *
   * @param {Window|number} window
   * @returns {undefined}
   */
  static CloseWindow(window) {
    return this.call(this.lvo.CloseWindow, { a0: ptrOf(window) });
  }

  static MoveWindow(window, dx, dy) {
    return this.call(this.lvo.MoveWindow, {
      a0: ptrOf(window), d0: dx | 0, d1: dy | 0,
    });
  }

  static SizeWindow(window, dw, dh) {
    return this.call(this.lvo.SizeWindow, {
      a0: ptrOf(window), d0: dw | 0, d1: dh | 0,
    });
  }

  static WindowToFront(window) {
    return this.call(this.lvo.WindowToFront, { a0: ptrOf(window) });
  }

  static WindowToBack(window) {
    return this.call(this.lvo.WindowToBack, { a0: ptrOf(window) });
  }

  static ActivateWindow(window) {
    return this.call(this.lvo.ActivateWindow, { a0: ptrOf(window) });
  }

  static BeginRefresh(window) {
    return this.call(this.lvo.BeginRefresh, { a0: ptrOf(window) });
  }

  static EndRefresh(window, complete) {
    return this.call(this.lvo.EndRefresh, {
      a0: ptrOf(window), d0: complete ? 1 : 0,
    });
  }

  /* ============================================================
   * Screen lifecycle
   * ============================================================ */

  static OpenScreenTagList(newScreen, tagList) {
    let raw = this.call(this.lvo.OpenScreenTagList, {
      a0: ptrOf(newScreen), a1: ptrOf(tagList),
    });

    return raw ? new Screen(raw) : null;
  }

  static OpenScreenTags(pairs) {
    let tags = globalThis.amiga.makeTags(pairs);
    let bytes = (pairs.length + 1) * 8;

    try {
      return this.OpenScreenTagList(null, tags);
    }

    finally {
      globalThis.amiga.freeMem(tags, bytes);
    }
  }

  static CloseScreen(screen) {
    return this.call(this.lvo.CloseScreen, { a0: ptrOf(screen) });
  }

  static ScreenToFront(screen) {
    return this.call(this.lvo.ScreenToFront, { a0: ptrOf(screen) });
  }

  static ScreenToBack(screen) {
    return this.call(this.lvo.ScreenToBack, { a0: ptrOf(screen) });
  }

  /**
   * Lock the named public screen (NULL = default Workbench).
   *
   * @param {string|number|null} name
   * @returns {Screen|null}
   */
  static LockPubScreen(name) {
    let namePtr = ptrOf(name);
    let bytes = 0;

    if (typeof name === 'string') {
      bytes = name.length + 1;
      namePtr = globalThis.amiga.allocMem(bytes);
      globalThis.amiga.pokeString(namePtr, name);
    }

    try {
      let raw = this.call(this.lvo.LockPubScreen, { a0: namePtr });

      return raw ? new Screen(raw) : null;
    }

    finally {
      if (bytes) globalThis.amiga.freeMem(namePtr, bytes);
    }
  }

  static UnlockPubScreen(name, screen) {
    return this.call(this.lvo.UnlockPubScreen, {
      a0: ptrOf(name), a1: ptrOf(screen),
    });
  }

  /* ============================================================
   * BOOPSI
   * ============================================================ */

  /**
   * NewObjectA(class, classID, tagList) — a0/a1/a2.
   *
   * @param {number} klass class pointer (NULL for public class by name)
   * @param {string|number} classID class ID string or NULL
   * @param {number|null} tagList
   * @returns {Image|number|null} Image wrapper for image classes; raw
   *   pointer otherwise; null on failure
   */
  static NewObjectA(klass, classID, tagList) {
    let idPtr = ptrOf(classID);
    let bytes = 0;

    if (typeof classID === 'string') {
      bytes = classID.length + 1;
      idPtr = globalThis.amiga.allocMem(bytes);
      globalThis.amiga.pokeString(idPtr, classID);
    }

    try {
      let raw = this.call(this.lvo.NewObjectA, {
        a0: ptrOf(klass), a1: idPtr, a2: ptrOf(tagList),
      });

      if (!raw) return null;

      /* Heuristic: image classes typically end in 'image' or contain
       * 'iclass'. Wrap in Image for those. Caller can re-wrap manually
       * if heuristic missed. */
      if (typeof classID === 'string' &&
          (classID.endsWith('image') || classID.includes('iclass'))) {
        return new Image(raw);
      }

      return raw;
    }

    finally {
      if (bytes) globalThis.amiga.freeMem(idPtr, bytes);
    }
  }

  /**
   * NewObjectA convenience taking a JS array of [tag, data] pairs.
   *
   * @param {string|number} classID
   * @param {Array<[number, number]>} pairs
   * @returns {Image|number|null}
   */
  static NewObjectTags(classID, pairs) {
    let tags = globalThis.amiga.makeTags(pairs);
    let bytes = (pairs.length + 1) * 8;

    try {
      return this.NewObjectA(0, classID, tags);
    }

    finally {
      globalThis.amiga.freeMem(tags, bytes);
    }
  }

  static DisposeObject(obj) {
    return this.call(this.lvo.DisposeObject, { a0: ptrOf(obj) });
  }

  static SetAttrsA(obj, tagList) {
    return this.call(this.lvo.SetAttrsA, {
      a0: ptrOf(obj), a1: ptrOf(tagList),
    });
  }

  static SetAttrsTags(obj, pairs) {
    let tags = globalThis.amiga.makeTags(pairs);
    let bytes = (pairs.length + 1) * 8;

    try {
      return this.SetAttrsA(obj, tags);
    }

    finally {
      globalThis.amiga.freeMem(tags, bytes);
    }
  }

  /* ============================================================
   * Misc
   * ============================================================ */

  static DrawImage(rport, image, x, y) {
    return this.call(this.lvo.DrawImage, {
      a0: ptrOf(rport), a1: ptrOf(image),
      d0: x | 0, d1: y | 0,
    });
  }

  static DisplayBeep(screen) {
    return this.call(this.lvo.DisplayBeep, { a0: ptrOf(screen) });
  }
}


/* === index.js === */
/* quickjs-master/amiga/ffi/index.js
 *
 * Q2 FFI entry point. Places every wrapper on the `amiga` namespace
 * under its canonical Amiga-library home, then re-exports to
 * globalThis if the slot is free.
 *
 * Placement rule (settled):
 *
 *   Library wrappers (the class that models a .library):
 *     amiga.<ClassName>
 *     globalThis.<ClassName>           (if !in globalThis)
 *
 *   Struct wrappers (a struct type owned by an Amiga library):
 *     amiga.<libname>.<StructName>     — "proper home"
 *     globalThis.<StructName>          (if !in globalThis)
 *
 *   Meta / base classes (LibraryBase, CEnumeration, Struct):
 *     amiga.<ClassName>
 *     globalThis.<ClassName>           (if !in globalThis)
 *
 *   Helpers (ptrOf, withStruct): globalThis only.
 *   makeTags / withTags are Q1 natives — NOT re-exposed here.
 *
 * Eval order at qjs startup:
 *   1. extended.js (qjsc_extended) installs `globalThis.amiga` with
 *      the Q1 FFI primitives and the lowercase per-library tables
 *      (amiga.intuition, amiga.graphics, amiga.exec, …) each
 *      holding `.lvo` and plain flag constants.
 *   2. ffi-bundle (qjsc_ffi) evaluates this file. By now the
 *      lowercase tables are guaranteed populated, so the static
 *      field `static lvo = globalThis.amiga.<lib>.lvo` on each
 *      library wrapper resolves cleanly.
 */




globalThis.amiga = globalThis.amiga || {};

/* Ensure the lowercase per-library tables exist. extended.js
 * normally creates them; this guards standalone bundle evaluation
 * during host-side testing. */
for (const libname of ['intuition', 'graphics', 'exec', 'dos', 'devices']) {
  if (!globalThis.amiga[libname]) globalThis.amiga[libname] = {};
}

/* ------------------------------------------------------------------
 * Library wrappers — amiga.<ClassName>
 * ------------------------------------------------------------------ */
const libs = {
  Exec, Dos, Intuition, Graphics, GadTools, Asl,
};

for (const [name, cls] of Object.entries(libs)) {
  globalThis.amiga[name] = cls;
}

/* ------------------------------------------------------------------
 * Struct wrappers — amiga.<libname>.<StructName>
 *
 * Ownership mapping follows NDK 3.2R4 header provenance:
 *   intuition/screens.h,intuition.h   → Window, NewWindow, Screen,
 *                                        IntuiMessage, Image, Gadget
 *   graphics/rastport.h, text.h       → RastPort, TextAttr
 *   exec/ports.h                      → MsgPort
 * ------------------------------------------------------------------ */
const structsByLib = {
  intuition: {
    Window, NewWindow, Screen, IntuiMessage, Image, Gadget,
    DrawInfo, Menu, MenuItem, IntuiText,
  },
  graphics:  { RastPort, TextAttr, BitMap, ColorMap },
  exec:      { MsgPort, IORequest },
  dos:       { FileInfoBlock },
  /* timer.device / inputevent.device live under "devices" in the
   * NDK; mirror that. */
  devices:   { TimerRequest, InputEvent },
};

for (const [libname, members] of Object.entries(structsByLib)) {
  for (const [name, cls] of Object.entries(members)) {
    globalThis.amiga[libname][name] = cls;
  }
}

/* ------------------------------------------------------------------
 * Meta / base classes — amiga.<ClassName>
 * ------------------------------------------------------------------ */
globalThis.amiga.LibraryBase  = LibraryBase;
globalThis.amiga.CEnumeration = CEnumeration;
globalThis.amiga.Struct       = Struct;

/* ------------------------------------------------------------------
 * Globals — convenience for scripts, conflict-gated.
 * ------------------------------------------------------------------ */
const everyGlobal = {
  /* meta */
  LibraryBase, CEnumeration, Struct,
  /* libs */
  Exec, Dos, Intuition, Graphics, GadTools, Asl,
  /* structs */
  Window, NewWindow, Screen, RastPort, MsgPort,
  IntuiMessage, TextAttr, Image, Gadget,
  DrawInfo, Menu, MenuItem, IntuiText, BitMap, ColorMap,
  FileInfoBlock, InputEvent, IORequest, TimerRequest,
  /* helpers (makeTags/withTags intentionally omitted — Q1 natives) */
  ptrOf, withStruct,
};

for (const [name, cls] of Object.entries(everyGlobal)) {
  if (!(name in globalThis)) {
    globalThis[name] = cls;
  }
}

/* Register the close-all exit hook so scripts that exit early or
 * throw don't leak library bases. Best-effort — qjs:os doesn't
 * currently expose setExitHook on Amiga; users can call
 * LibraryBase.closeAll() manually at script end if needed. */
try {
  let os = globalThis.__qjs_os;

  if (os && typeof os.setExitHook === 'function') {
    os.setExitHook(() => LibraryBase.closeAll());
  }
}

catch (_) {
  /* no-op */
}


